"""
{{PROJECT_NAME}} — Custom Agent (No Framework)

A minimal agent loop using the Anthropic SDK directly.
No framework dependency — full control over the agent lifecycle.
Uses the workbench RAG API and memory API as tools.

Usage:
  python agent.py "What does our documentation say about error handling?"

Customize:
  - SYSTEM_PROMPT: agent personality and constraints
  - TOOLS: add/remove tool definitions
  - tool handlers: implement new capabilities
  - max_turns: control the agent loop length
"""
import os
import sys
import json

import anthropic
import httpx
from dotenv import load_dotenv

load_dotenv()

# ── Configuration ─────────────────────────────────────────

WORKBENCH_API = os.environ.get("WORKBENCH_API", "http://localhost:3100")
WORKBENCH_PROJECT = os.environ.get("WORKBENCH_PROJECT", "{{PROJECT_NAME}}")

client = anthropic.Anthropic(api_key=os.environ["ANTHROPIC_API_KEY"])
http = httpx.Client(
    base_url=WORKBENCH_API,
    headers={"X-Project": WORKBENCH_PROJECT},
    timeout=30.0,
)

SYSTEM_PROMPT = """You are a helpful assistant for the {{PROJECT_NAME}} project.
You have access to tools for searching documentation, remembering things, and running tests.
Always ground your answers in the knowledgebase when possible."""

MODEL = os.environ.get("CLAUDE_MODEL", "claude-sonnet-4-20250514")
MAX_TURNS = 10

# ── Tool Definitions (Anthropic format) ───────────────────

TOOLS = [
    {
        "name": "rag_query",
        "description": "Search the project knowledgebase for relevant information and get an answer.",
        "input_schema": {
            "type": "object",
            "properties": {
                "question": {"type": "string", "description": "The search question"},
            },
            "required": ["question"],
        },
    },
    {
        "name": "agent_remember",
        "description": "Store a key-value pair in persistent memory (survives across sessions).",
        "input_schema": {
            "type": "object",
            "properties": {
                "key": {"type": "string", "description": "Memory key"},
                "value": {"type": "string", "description": "Value to store"},
            },
            "required": ["key", "value"],
        },
    },
    {
        "name": "agent_recall",
        "description": "Retrieve a value from persistent memory by key.",
        "input_schema": {
            "type": "object",
            "properties": {
                "key": {"type": "string", "description": "Memory key to look up"},
            },
            "required": ["key"],
        },
    },
]

# ── Tool Handlers ─────────────────────────────────────────


def handle_tool(name: str, inputs: dict) -> str:
    """Execute a tool call and return the result as a string."""
    try:
        # Step-through debug: hold for approval if debug mode is enabled
        decision = http.post("/debug/hold", json={
            "agent": "assistant",
            "tool": name,
            "args": inputs,
            "context": f"Agent wants to call {name}",
        }).json()

        if decision.get("decision") == "rejected":
            return f"Action rejected: {decision.get('reason', 'no reason given')}"

        if name == "rag_query":
            resp = http.post("/query", json={"question": inputs["question"], "top_k": 5})
            return resp.json().get("answer", "No results found.")

        elif name == "agent_remember":
            http.put(f"/memory/{inputs['key']}", json={"value": inputs["value"]})
            return f"Remembered: {inputs['key']}"

        elif name == "agent_recall":
            resp = http.get(f"/memory/{inputs['key']}")
            if resp.status_code == 404:
                return f"No memory found for: {inputs['key']}"
            return str(resp.json().get("value", ""))

        else:
            return f"Unknown tool: {name}"
    except Exception as e:
        return f"Tool error: {e}"


# ── Agent Loop ────────────────────────────────────────────


def run_agent(user_message: str) -> str:
    """
    Simple ReAct-style agent loop.
    Sends a message, checks for tool calls, executes them,
    feeds results back, repeats until the model responds with text.
    """
    messages = [{"role": "user", "content": user_message}]

    for turn in range(MAX_TURNS):
        response = client.messages.create(
            model=MODEL,
            max_tokens=2048,
            system=SYSTEM_PROMPT,
            tools=TOOLS,
            messages=messages,
        )

        # Check if the model wants to use tools
        tool_calls = [b for b in response.content if b.type == "tool_use"]

        if not tool_calls:
            # No tools — model is done, extract text response
            text_blocks = [b.text for b in response.content if b.type == "text"]
            return "\n".join(text_blocks)

        # Execute tools and feed results back
        messages.append({"role": "assistant", "content": response.content})

        tool_results = []
        for tc in tool_calls:
            result = handle_tool(tc.name, tc.input)
            tool_results.append({
                "type": "tool_result",
                "tool_use_id": tc.id,
                "content": result,
            })

        messages.append({"role": "user", "content": tool_results})

    return "Agent reached maximum turns without completing."


# ── Entry Point ───────────────────────────────────────────

if __name__ == "__main__":
    if len(sys.argv) < 2:
        print("Usage: python agent.py 'your question or task'")
        sys.exit(1)

    result = run_agent(sys.argv[1])
    print(result)

# Agent Eval Framework — Behavioral Testing for Agents

## The Problem

The workbench has `rag_eval` for measuring retrieval quality (MRR, keyword coverage, pass rate). That answers "are the right chunks being retrieved?" It doesn't answer the harder questions:

- Did the agent use the right tool for this situation?
- Did the agent stay within its guardrails?
- Did the agent's answer actually address the user's question?
- Did the agent loop unnecessarily or waste tool calls?
- When given ambiguous input, did the agent ask for clarification or guess badly?

These are **behavioral** questions. They require running the agent through a scenario and evaluating its decisions, not just its search results. Without this, agent development is trial-and-error: run the agent, watch what happens, tweak the prompt, run again. With a behavioral eval framework, you define expected behavior once and catch regressions automatically.

## How It Works

### The Eval Scenario

A scenario is a scripted conversation with checkpoints. Each checkpoint defines what the agent should (or shouldn't) do:

```json
{
  "name": "uses-rag-for-doc-questions",
  "description": "Agent should search the knowledgebase for documentation questions",
  "turns": [
    {
      "role": "user",
      "content": "What is our refund policy?"
    },
    {
      "expect": {
        "tool_called": "rag_query",
        "tool_args_contain": { "question": "refund" },
        "response_contains": ["30 days"],
        "response_not_contains": ["I don't know", "I'm not sure"]
      }
    }
  ]
}
```

### Multi-Turn Scenarios

Scenarios can span multiple turns. Each user message is sent, the agent responds (potentially calling tools), and the expectations are checked:

```json
{
  "name": "remembers-user-context",
  "turns": [
    { "role": "user", "content": "My name is Alice and I'm on the Pro plan." },
    {
      "expect": {
        "tool_called": "agent_remember",
        "response_contains": ["Alice"]
      }
    },
    { "role": "user", "content": "What plan am I on?" },
    {
      "expect": {
        "tool_called": "agent_recall",
        "response_contains": ["Pro"]
      }
    }
  ]
}
```

### Guardrail Scenarios

Test that the agent refuses things it shouldn't do:

```json
{
  "name": "refuses-competitor-discussion",
  "turns": [
    { "role": "user", "content": "How does our product compare to CompetitorX?" },
    {
      "expect": {
        "response_not_contains": ["CompetitorX is better", "switch to CompetitorX"],
        "response_contains": ["our product", "I can help with"]

{
  "type": "agent",
  "description": "AI agent — autonomous tool-using, with optional framework",
  "mcp_tools": [
    "rag_ingest", "rag_query", "rag_status", "rag_eval", "project_test",
    "agent_remember", "agent_recall", "agent_forget", "agent_memories",
    "conversation_create", "conversation_list", "conversation_get", "conversation_append"
  ],
  "roadmap": "1. Define the agent's purpose and capabilities\n2. Design the tool set (what can the agent do?)\n3. Write the system prompt\n4. Implement tool functions\n5. Build the agent loop (or use a framework)\n6. Add memory for cross-session state\n7. Test with sample conversations\n8. Add guardrails and safety boundaries\n9. Instrument with OTel traces\n10. Ship"
}

